"use client";

import { useState, useRef } from "react";
import {
    Download,
    Image as ImageIcon,
    FileText,
    Loader2,
    X,
    ZoomIn,
    ZoomOut,
} from "lucide-react";

interface ExportTreeProps {
    treeContainerRef: React.RefObject<HTMLDivElement | null>;
    baniName: string;
}

export default function ExportTree({ treeContainerRef, baniName }: ExportTreeProps) {
    const [exporting, setExporting] = useState(false);
    const [showOptions, setShowOptions] = useState(false);
    const [error, setError] = useState("");

    const exportAsImage = async () => {
        if (!treeContainerRef.current) return;
        setExporting(true);
        setError("");

        try {
            const html2canvas = (await import("html2canvas")).default;
            const canvas = await html2canvas(treeContainerRef.current, {
                backgroundColor: "#ffffff",
                scale: 2,
                useCORS: true,
                logging: false,
                windowWidth: treeContainerRef.current.scrollWidth,
                windowHeight: treeContainerRef.current.scrollHeight,
            });

            const link = document.createElement("a");
            link.download = `${baniName.replace(/\s+/g, "-")}-tree.png`;
            link.href = canvas.toDataURL("image/png");
            link.click();
        } catch (err) {
            console.error("Export image error:", err);
            setError("Gagal mengekspor gambar");
        } finally {
            setExporting(false);
            setShowOptions(false);
        }
    };

    const exportAsPDF = async () => {
        if (!treeContainerRef.current) return;
        setExporting(true);
        setError("");

        try {
            const html2canvas = (await import("html2canvas")).default;
            const { jsPDF } = await import("jspdf");

            const canvas = await html2canvas(treeContainerRef.current, {
                backgroundColor: "#ffffff",
                scale: 2,
                useCORS: true,
                logging: false,
                windowWidth: treeContainerRef.current.scrollWidth,
                windowHeight: treeContainerRef.current.scrollHeight,
            });

            const imgData = canvas.toDataURL("image/png");
            const imgWidth = canvas.width;
            const imgHeight = canvas.height;

            // Determine orientation based on aspect ratio
            const isLandscape = imgWidth > imgHeight;
            const pdf = new jsPDF({
                orientation: isLandscape ? "landscape" : "portrait",
                unit: "mm",
            });

            const pageWidth = pdf.internal.pageSize.getWidth();
            const pageHeight = pdf.internal.pageSize.getHeight();

            // Add header
            pdf.setFontSize(16);
            pdf.setFont("helvetica", "bold");
            pdf.text(baniName, pageWidth / 2, 15, { align: "center" });
            pdf.setFontSize(10);
            pdf.setFont("helvetica", "normal");
            pdf.text("Silsilah Keluarga — Jejak Nasab", pageWidth / 2, 22, {
                align: "center",
            });

            // Calculate image dimensions to fit page
            const margin = 10;
            const headerHeight = 30;
            const availWidth = pageWidth - margin * 2;
            const availHeight = pageHeight - headerHeight - margin;

            let finalWidth = availWidth;
            let finalHeight = (imgHeight / imgWidth) * availWidth;

            if (finalHeight > availHeight) {
                finalHeight = availHeight;
                finalWidth = (imgWidth / imgHeight) * availHeight;
            }

            const xOffset = (pageWidth - finalWidth) / 2;
            pdf.addImage(imgData, "PNG", xOffset, headerHeight, finalWidth, finalHeight);

            // Add footer
            pdf.setFontSize(8);
            pdf.setTextColor(150);
            const today = new Date().toLocaleDateString("id-ID", {
                day: "numeric",
                month: "long",
                year: "numeric",
            });
            pdf.text(
                `Dicetak dari Jejak Nasab — ${today}`,
                pageWidth / 2,
                pageHeight - 5,
                { align: "center" }
            );

            pdf.save(`${baniName.replace(/\s+/g, "-")}-tree.pdf`);
        } catch (err) {
            console.error("Export PDF error:", err);
            setError("Gagal mengekspor PDF");
        } finally {
            setExporting(false);
            setShowOptions(false);
        }
    };

    return (
        <div className="relative">
            <button
                onClick={() => setShowOptions(!showOptions)}
                disabled={exporting}
                className="touch-target flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white border border-surface-200 text-surface-700 text-sm font-medium hover:bg-surface-50 transition-colors disabled:opacity-50"
            >
                {exporting ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                    <Download className="w-4 h-4" />
                )}
                Ekspor
            </button>

            {showOptions && (
                <>
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setShowOptions(false)}
                    />
                    <div className="absolute right-0 top-full mt-2 w-52 rounded-xl bg-white border border-surface-200 shadow-xl z-50 overflow-hidden">
                        <button
                            onClick={exportAsImage}
                            disabled={exporting}
                            className="w-full flex items-center gap-3 px-4 py-3 text-sm text-surface-700 hover:bg-surface-50 transition-colors disabled:opacity-50"
                        >
                            <ImageIcon className="w-4 h-4 text-blue-500" />
                            Simpan sebagai PNG
                        </button>
                        <button
                            onClick={exportAsPDF}
                            disabled={exporting}
                            className="w-full flex items-center gap-3 px-4 py-3 text-sm text-surface-700 hover:bg-surface-50 transition-colors border-t border-surface-100 disabled:opacity-50"
                        >
                            <FileText className="w-4 h-4 text-red-500" />
                            Simpan sebagai PDF
                        </button>
                    </div>
                </>
            )}

            {error && (
                <div className="absolute right-0 top-full mt-2 p-3 rounded-xl bg-red-50 border border-red-200 text-red-600 text-xs flex items-center gap-2 z-50">
                    <X className="w-3 h-3" />
                    {error}
                </div>
            )}
        </div>
    );
}
